#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=3000005,mod=1e9+7;
ll n,m,mx,jc[N],ny[N];
ll C(int x,int y)
{
	if((y<0)||(x<0)) return 0;
	return jc[x+y]*ny[y]%mod*ny[x]%mod;
}
void init()
{
	jc[0]=ny[0]=ny[1]=1;
	for(int i=1;i<=N-5;i++) jc[i]=i*jc[i-1]%mod;
	for(int i=2;i<=N-5;i++) ny[i]=(mod-mod/i)*ny[mod%i]%mod;
	for(int i=1;i<=N-5;i++) ny[i]=ny[i]*ny[i-1]%mod;
}
void fanshe1(ll &x,ll &y)
{
	swap(x,y);
	x--;
	y++;
}
void fanshe2(ll &x,ll &y)
{
	swap(x,y);
	x+=(m+2);
	y-=(m+2);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	init();
	ll x=n+m+1,y=n,ans=C(x,y);
	while((x>=0)&&(y>=0))
	{
		fanshe1(x,y);
//		cout<<x<<" "<<y<<" ";
		ans=(ans-C(x,y)+mod)%mod;
//		cout<<C(x,y)<<" ";
		fanshe2(x,y);
//		cout<<C(x,y)<<"\n";
//		cout<<x<<" "<<y<<"\n";
		ans=(ans+C(x,y))%mod;
	}
	x=n+m+1,y=n;
	while((x>=0)&&(y>=0))
	{
		fanshe2(x,y);
//		cout<<x<<" "<<y<<" ";
		ans=(ans-C(x,y)+mod)%mod;
//		cout<<C(x,y)<<" ";
		fanshe1(x,y);
//		cout<<x<<" "<<y<<"\n";
		ans=(ans+C(x,y))%mod;
//		cout<<C(x,y)<<"\n";
	}
	cout<<ans<<"\n";
	return 0;
}
